const hourUTC = new Date().getUTCHours();
const label = (hourUTC >= 4 && hourUTC <= 6) ? 'morning'
            : (hourUTC >= 21 && hourUTC <= 23) ? 'evening'
            : 'manual';
const now = new Date();
const dayName = now.toLocaleDateString('en-GB', { weekday: 'short', day: 'numeric', month: 'short' });
return [{ json: { mode: label, day: dayName } }];

const d = $('Fetch Data').first().json;
const m = $('Build Mode').first().json;
const tg = $input.first().json.data.data;
const label = m.mode === 'morning' ? 'Morning Brief' : m.mode === 'evening' ? 'Nightly Close' : 'Test Fire';
const sov = d.sovereignty_pct == null ? 'no AI calls' : `${d.sovereignty_pct}% local (${d.local_calls}/${d.local_calls + d.cloud_calls})`;
const lines = [
  `<b>Home AI - ${label} - ${m.day}</b>`,
  '',
  '<b>Last 24h</b>',
  `* ${d.audit_success}OK / ${d.audit_failure}FAIL / ${d.audit_escalated}ESC AI calls`,
  `* ${d.events_processed} events processed, ${d.events_failed} failed, ${d.events_in_flight} in flight`,
  `* ${d.alerts_firing} firing alerts, ${d.dead_letters_open} open dead letters`,
  `* ${d.emails_24h} emails classified, ${d.invoices_needs_review} invoices need review`,
  '',
  '<b>Sovereignty &amp; spend</b>',
  `* ${sov}`,
  `* MTD cloud spend GBP ${Number(d.mtd_spend_gbp).toFixed(2)}`,
];
const healthy = Number(d.audit_failure)===0 && Number(d.alerts_firing)===0 && Number(d.dead_letters_open)===0;
lines.push('');
lines.push(healthy ? '<i>System healthy</i>' : '<i>Items need attention</i>');
return [{ json: { chat_id: tg.chat_id, bot_token: tg.bot_token, text: lines.join('\n') } }];
